/// <summary>
/// This class is an extension of form InventJournalName.
/// </summary>
[ExtensionOf(formStr(InventJournalName))]
internal final class ETGInventJournalNameForm_Extension
{
}

Method.Source:
/// <summary>
/// When Cylindertracking feature is enabled, then only field is visible.
/// </summary>
public void init()
{
    next init();
    FormRun formRun = this as FormRun;
    formRun.design().controlName(FormControlstr(InventJournalName, InventJournalName_ETGManualAdditionorDeletion)).visible(SalesParameters::find().ETGEnableCylinderTracking);
}

/// <summary>
///
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[FormControlEventHandler(formControlStr(InventJournalName, InventJournalName_ETGReasonCode), FormControlEventType::Lookup)]
public static void InventJournalName_ETGReasonCode_OnLookup(FormControl sender, FormControlEventArgs e)
{
    SysTableLookup      sysTableLookup  = SysTableLookup::newParameters(tableNum(ETGReasonCodes), sender);

    // VendGroup columns presented to user
    sysTableLookup.addLookupfield(fieldNum(ETGReasonCodes, ReasonId));
    sysTableLookup.addLookupfield(fieldNum(ETGReasonCodes, Description));

    // Execute lookup
    sysTableLookup.performFormLookup();

    // Use FormControlCancelableSuperEventArgs to cancel call to super()
    FormControlCancelableSuperEventArgs cancelableSuperEventArgs = e as FormControlCancelableSuperEventArgs;
    cancelableSuperEventArgs.CancelSuperCall();
}
